function washDishesManually() {
    // Подготовка
    sink = getSink()
    sink.fillWithHotWater()
    dishSoap = getDishSoap()
    sink.addSoap(dishSoap)
    sink.stirUntilFoamy()

    dirtyDishes = getDirtyDishes()
    cleanDishes = []

    // Основной цикл мытья
    while (dirtyDishes.isNotEmpty()) {
        plate = dirtyDishes.pop()

        // Предварительное замачивание для сильно загрязненных предметов
        if (plate.isHeavilySoiled()) {
            sink.submerge(plate)
            wait(minutes = 3)
        }

        // Мытье
        sponge = getSponge()
        sponge.wet()
        plate.scrub(sponge, focus = "allCornersAndCreases")

        // Промывание
        faucet = getFaucet()
        faucet.setMode("spray") // Использование насадки-распылителя
        plate.rinseUnder(faucet)

        // Сушка
        dryingRack = getDryingRack()
        dryingRack.place(plate)
        cleanDishes.add(plate)
    }

    // Ожидание высыхания и уборка
    while (cleanDishes.hasWetItems()) {
        wait(time = "airDry")
    }

    for (plate in cleanDishes) {
        cabinet = getCabinet()
        cabinet.store(plate)
    }

    // Завершение и уборка раковины
    sink.drain()
    cleanCloth = getCleanCloth()
    sink.wipe(cleanCloth)
    countertop.wipe(cleanCloth)

    print("Посуда вымыта и убрана!")
}
